#include <bits/stdc++.h>
using namespace std;
int n,m,dp[1<<18][20],a[20][20];
int main()
{
    cin>>n>>m;
    memset(a,128,sizeof(a));
    for(int i=1;i<=m;i++)
    {
        int x,y,z;
        cin>>x>>y>>z;
        a[x][y]=z;
    }
    for(int i=3;i<(1<<n);i++)
    {
        for(int j=0;j<n;j++)
        {
            if(((1<<j)&i)==0) continue;
            dp[i][j]=-0x3f3f3f3f;
            for(int k=0;k<n;k++)
            {
                if(k==j||((1<<k)&i)==0||a[k][j]<=0) continue;
                dp[i][j]=max(dp[i][j],dp[i-(1<<j)][k]+a[k][j]);
            }
        }
    }
    int ans=0;
    for(int i=1+(1<<(n-1));i<(1<<n);i++)
    {
        ans=max(ans,dp[i][n-1]);
    }
    cout<<ans;
    return 0;
}
